import{c as e,Q as s,j as i,m as t}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"SOP-001: Installation & Setup Guide","description":"SOP guide to install, configure, and boot the AI Workflow Orchestrator application","frontmatter":{"title":"SOP-001: Installation & Setup Guide","description":"SOP guide to install, configure, and boot the AI Workflow Orchestrator application","keywords":"installation guide, environment setup, python uvicorn, api rotation, key manager, mongodb setup","robots":"index, follow"},"headers":[],"relativePath":"en/sop/setup.md","filePath":"en/sop/setup.md","lastUpdated":null}'),n={name:"en/sop/setup.md"};function o(r,a,l,p,h,d){return s(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="🛠️-sop-001-installation-setup-guide" tabindex="-1">🛠️ SOP-001: Installation &amp; Setup Guide <a class="header-anchor" href="#🛠️-sop-001-installation-setup-guide" aria-label="Permalink to &quot;🛠️ SOP-001: Installation &amp; Setup Guide&quot;">​</a></h1><p>This Standard Operating Procedure (SOP) runbook provides step-by-step instructions for setting up workspace environments, installing dependencies, binding LLM API keys, managing rotation schemas, and executing the <strong>AI Workflow Orchestrator</strong>.</p><hr><h2 id="📋-1-prerequisites-system-constraints" tabindex="-1">📋 1. Prerequisites &amp; System Constraints <a class="header-anchor" href="#📋-1-prerequisites-system-constraints" aria-label="Permalink to &quot;📋 1. Prerequisites &amp; System Constraints&quot;">​</a></h2><p>Ensure the host environment meets the following specifications:</p><ul><li><strong>OS:</strong> Linux (Ubuntu 20.04+ recommended) or macOS.</li><li><strong>Python version:</strong> <code>3.10</code> or newer (<code>3.11</code> compatible).</li><li><strong>Disk Space:</strong> At least <code>500MB</code> available space for runtime logs, trace artifacts, and SQLite database storage.</li></ul><hr><h2 id="💾-2-clone-workspace-install-requirements" tabindex="-1">💾 2. Clone Workspace &amp; Install Requirements <a class="header-anchor" href="#💾-2-clone-workspace-install-requirements" aria-label="Permalink to &quot;💾 2. Clone Workspace &amp; Install Requirements&quot;">​</a></h2><p>Execute the following terminal commands to fetch the repository and resolve packages:</p><ol><li><p><strong>Clone the code repository:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/kiza101288/ai-workflow-orchestrator.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ai-workflow-orchestrator</span></span></code></pre></div></li><li><p><strong>Scaffold and load a dedicated Python virtual environment:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> venv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> venv</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> venv/bin/activate</span></span></code></pre></div></li><li><p><strong>Install pinned dependencies:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --upgrade</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pip</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> requirements.txt</span></span></code></pre></div></li></ol><hr><h2 id="🔑-3-api-key-mapping-rotation-schemas" tabindex="-1">🔑 3. API Key Mapping &amp; Rotation Schemas <a class="header-anchor" href="#🔑-3-api-key-mapping-rotation-schemas" aria-label="Permalink to &quot;🔑 3. API Key Mapping &amp; Rotation Schemas&quot;">​</a></h2><p>The orchestration core integrates a dynamic <strong>KeyManager</strong> to manage Gemini API credentials. If an API request trips rate limit boundaries (HTTP 429), the KeyManager automatically flags the blocked credential, removes it from the active rotation pool, and transparently routes execution to the next available key.</p><h3 id="loading-api-credentials-via-environment-variables" tabindex="-1">Loading API credentials via environment variables: <a class="header-anchor" href="#loading-api-credentials-via-environment-variables" aria-label="Permalink to &quot;Loading API credentials via environment variables:&quot;">​</a></h3><p>Inject your Gemini credentials as a comma-separated array inside the <code>GOOGLE_API_KEY</code> configuration:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> GOOGLE_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;AIzaSyA1...,AIzaSyA2...,AIzaSyA3...&quot;</span></span></code></pre></div><p>The KeyManager inside [key_manager.py](file:///home/kizabgd/.gemini/extensions/ai-workflow-orchestrator/core/key_manager.py) will dynamically split these strings and rotate them using a round-robin schema during agent turns.</p><hr><h2 id="☁️-4-mongodb-atlas-cloud-memory-integration" tabindex="-1">☁️ 4. MongoDB Atlas Cloud Memory Integration <a class="header-anchor" href="#☁️-4-mongodb-atlas-cloud-memory-integration" aria-label="Permalink to &quot;☁️ 4. MongoDB Atlas Cloud Memory Integration&quot;">​</a></h2><p>To index long-term forensic logs and execute Vector similarity lookups of past arguments, the orchestrator connects to MongoDB Atlas.</p><ol><li><strong>Fetch your MongoDB connection URI from the Atlas Console</strong> (verify that your host or container IP address is whitelisted in the Network Access security tab).</li><li><strong>Inject the environment variable:</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> MONGODB_URI</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mongodb+srv://&lt;user&gt;:&lt;password&gt;@cluster.mongodb.net/?retryWrites=true&amp;w=majority&quot;</span></span></code></pre></div></li><li><strong>Database and Collections Scaffold:</strong> The database target is set to <code>ai_workflow_orchestrator</code>. Upon initial connection, the MongoDBMemory connector automatically indexes the <code>debates</code>, <code>arguments</code>, and <code>decision_history</code> collections.</li></ol><p><em>If <code>MONGODB_URI</code> remains empty or network connections fail, the memory layer automatically activates a local failover cache pointing to the SQLite database at <code>storage/memory.db</code>.</em></p><hr><h2 id="🔒-5-bypassing-workspace-verification-in-non-production-envs" tabindex="-1">🔒 5. Bypassing Workspace Verification in Non-Production Envs <a class="header-anchor" href="#🔒-5-bypassing-workspace-verification-in-non-production-envs" aria-label="Permalink to &quot;🔒 5. Bypassing Workspace Verification in Non-Production Envs&quot;">​</a></h2><p>The zero-trust <code>IdentityGuard</code> in <code>core/identity.py</code> verifies environment parameters before starting. It expects <code>GOOGLE_CLOUD_PROJECT</code> to map exactly to <code>sixth-hawk-492717-m1</code> and <code>MONGODB_DATABASE</code> to <code>ai_workflow_orchestrator</code>.</p><p>If you run the application in a local testing sandbox or public demonstration environment (e.g. Hugging Face Spaces), the identity check will block startup. To bypass this lock safely:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> SKIP_IDENTITY_CHECK</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">true</span></span></code></pre></div><hr><h2 id="🏃-6-running-the-system" tabindex="-1">🏃 6. Running the System <a class="header-anchor" href="#🏃-6-running-the-system" aria-label="Permalink to &quot;🏃 6. Running the System&quot;">​</a></h2><p>You can run the orchestrator through two interfaces:</p><h3 id="interface-a-cli-runner-terminal-execution" tabindex="-1">Interface A: CLI Runner (Terminal Execution) <a class="header-anchor" href="#interface-a-cli-runner-terminal-execution" aria-label="Permalink to &quot;Interface A: CLI Runner (Terminal Execution)&quot;">​</a></h3><p>To submit a single natural language task and display the multi-round debate sequence in your terminal:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.py</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;deploy a secure database cluster on GKE&quot;</span></span></code></pre></div><h3 id="interface-b-fastapi-server-web-dashboard" tabindex="-1">Interface B: FastAPI Server &amp; Web Dashboard <a class="header-anchor" href="#interface-b-fastapi-server-web-dashboard" aria-label="Permalink to &quot;Interface B: FastAPI Server &amp; Web Dashboard&quot;">​</a></h3><p>To start the FastAPI web server serving Uvicorn bindings and host the HTML frontend dashboard on port <code>7860</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> uvicorn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> api.routes:app</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --host</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.0.0.0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --port</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 7860</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --reload</span></span></code></pre></div><p>Once initialized, navigate your browser to <code>http://localhost:7860</code> to access the premium glassmorphism dashboard, displaying real-time debate flows, agent opinons, and pipeline traces.</p>`,37)])])}const k=e(n,[["render",o]]);export{g as __pageData,k as default};
